const isNeighbor = ([x1, y1]: Cell, [x2, y2]: Cell): boolean =>
  Math.abs(x1 - x2) <= 1 &&
  Math.abs(y1 - y2) <= 1 &&
  !(x1 === x2 && y1 === y2);

export const nextGeneration = (cells: Cell[]): Cell[] =>
  cells.filter(
    (cell) => cells.filter((other) => isNeighbor(cell, other)).length === 2
  );
